const fs = require('fs');
const path = require('path');

function escribir(rutaRelativa, b64) {
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(rutaRelativa);
  if (dir && dir !== '.') fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(rutaRelativa, content, 'utf8');
  console.log('OK:', rutaRelativa);
}

// Fix visual: el header de /vet usaba un degradado que se aclaraba
// justo donde esta el texto blanco (nombre, especie, etc.), haciendo
// que se perdiera la lectura hacia el final. Ahora el cafe oscuro se
// mantiene solido hasta el 70% de la altura (donde vive todo el
// texto), y solo transiciona a claro en el ultimo tramo, como fondo
// decorativo.
escribir(path.join('app', 'vet', 'page.tsx'), '');

